export function getVisibleStudents(role: UserRole, userId: string): MockStudent[] {
  if (role === 'teacher') {
    return mockStudents.filter((student) => student.teacherId === userId);
  }
  if (role === 'admin' || role === 'super-admin') {
    return mockStudents;
  }
  return [];
}

export function getStudentById(studentId: string): MockStudent | undefined {
  return mockStudents.find((student) => student.id === studentId);
}

export function canManageStudent(currentUser: MockUser, student: MockStudent): boolean {
  if (currentUser.role === 'teacher') {
    return student.teacherId === currentUser.id;
  }
  return currentUser.role === 'admin' || currentUser.role === 'super-admin';
}
